class WordFilter:
    def __init__(self, words: List[str]):
        self.d = {}
        for i, w in enumerate(words):
            for p in range(len(w)+1):
                for s in range(len(w)+1):
                    self.d[w[:p]+"#"+w[len(w)-s:]] = i
    def f(self, prefix: str, suffix: str) -> int:
        return self.d.get(prefix+"#"+suffix, -1)

